    /// Gets the largest whole number value and its corresponding unit symbol.
    /// </summary>
    public string LargestWholeNumberSymbol
    {
        get
        {
            GetLargestWholeNumber(out _, out var symbol);
            return symbol;
        }
    }

    /// <summary>
    /// Gets the value in the largest whole number unit.
    /// </summary>
    public double LargestWholeNumberValue
    {
        get
        {
            GetLargestWholeNumber(out var value, out _);
            return value;
        }
    }

    private void GetLargestWholeNumber(out double value, out string symbol)
    {
        var tb = Terabytes;
        if (Math.Abs(tb) >= 1) { value = tb; symbol = TerabyteSymbol; return; }
        var gb = Gigabytes;
        if (Math.Abs(gb) >= 1) { value = gb; symbol = GigabyteSymbol; return; }
        var mb = Megabytes;
        if (Math.Abs(mb) >= 1) { value = mb; symbol = MegabyteSymbol; return; }
        var kb = Kilobytes;
        if (Math.Abs(kb) >= 1) { value = kb; symbol = KilobyteSymbol; return; }
        var bytes = Bytes;
        if (Math.Abs(bytes) >= 1) { value = bytes; symbol = ByteSymbol; return; }
        value = _bits; symbol = BitSymbol;
    }

